// Saves OHLCV candles to CSV in workspace/data/xauusd/
import pkg from 'dukascopy-node';
import fs from 'fs';
import path from 'path';

const { getHistoricalRates } = pkg;

// ---- config ----
const TF = process.env.TF || 'h1';
const FROM = process.env.FROM || '2024-01-01';
const TO = process.env.TO || '2026-07-19';
const OUT_DIR = path.resolve(process.cwd(), '..', 'data', 'xauusd');
const CACHE_DIR = path.resolve(process.cwd(), '.cache');
fs.mkdirSync(OUT_DIR, { recursive: true });
fs.mkdirSync(CACHE_DIR, { recursive: true });
const OUT_FILE = path.join(OUT_DIR, `xauusd_${TF}_${FROM}_${TO}.csv`);

const BATCH = parseInt(process.env.BATCH || '20', 10);
const PAUSE = parseInt(process.env.PAUSE || '120', 10);

console.log(`[cfg] instrument=xauusd tf=${TF} from=${FROM} to=${TO} batch=${BATCH} pause=${PAUSE}ms`);
console.log(`[cfg] out=${OUT_FILE}`);

const data = await getHistoricalRates({
  instrument: 'xauusd',
  dates: { from: new Date(`${FROM}T00:00:00Z`), to: new Date(`${TO}T00:00:00Z`) },
  timeframe: TF,
  format: 'json',
  useCache: true,
  cacheFolderPath: CACHE_DIR,
  batchSize: BATCH,
  pauseBetweenBatchesMs: PAUSE,
  retryCount: 5,
  pauseBetweenRetriesMs: 500,
  retryOnEmpty: true,
});

// de-dupe + sort by timestamp
const seen = new Set();
const rows = [];
for (const r of data) {
  const ts = Number(r.timestamp);
  if (seen.has(ts)) continue;
  seen.add(ts);
  const d = new Date(ts);
  const iso = d.toISOString().replace('T', ' ').replace('Z', '');
  rows.push([iso, r.open, r.high, r.low, r.close, r.volume ?? 0]);
}
rows.sort((a, b) => a[0] < b[0] ? -1 : 1);

let header = 'time_utc,open,high,low,close,volume\n';
const csv = header + rows.map(r => r.join(',')).join('\n') + '\n';
fs.writeFileSync(OUT_FILE, csv);

console.log(`[done] candles=${rows.length} -> ${OUT_FILE}`);
console.log('[first]', rows[0]);
console.log('[last ]', rows[rows.length - 1]);
"}
